"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/utils/cn";
import { Tooltip } from "@/components/Tooltip";

/* в”Җв”Җ FAB Variants в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
const fabVariants = cva(
  [
    "group inline-flex items-center justify-center shrink-0",
    "rounded-full font-medium select-none",
    "transition-[width,padding] duration-200 ease-in-out",
    "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
    "disabled:pointer-events-none disabled:opacity-40",
  ],
  {
    variants: {
      variant: {
        primary:   "bg-ac-primary-50 text-ac-white hover:bg-ac-primary-60 active:bg-ac-primary-70",
        secondary: "bg-ac-gray-90 text-ac-white hover:bg-ac-gray-80 active:bg-ac-gray-70",
        tertiary:  "bg-ac-gray-20 text-foreground border border-border hover:bg-ac-gray-30 active:bg-ac-gray-40",
      },
      size: {
        lg: "h-[48px] shadow-lg hover:shadow-xl",
        md: "h-[40px] shadow-md hover:shadow-lg",
      },
    },
    defaultVariants: {
      variant: "primary",
      size: "lg",
    },
  }
);

/* в”Җв”Җ Icon size map в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
const iconSizeMap: Record<string, string> = {
  lg: "h-6 w-6",
  md: "h-5 w-5",
};

function getIconSizeClass(size?: string | null) {
  return iconSizeMap[size ?? "lg"] ?? "h-6 w-6";
}

function cloneIconWithSize(icon: React.ReactNode, sizeClass: string) {
  if (!React.isValidElement(icon)) return icon;
  const el = icon as React.ReactElement<{ className?: string }>;
  return React.cloneElement(el, {
    className: cn(el.props.className, sizeClass),
  });
}

/* в”Җв”Җ Props в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
export interface FABProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof fabVariants> {
  /** м•„мқҙмҪҳ (н•„мҲҳ) вҖ” childrenмңјлЎң м „лӢ¬ */
  children: React.ReactNode;
  /**
   * л Ҳмқҙлё” н…ҚмҠӨнҠё
   * - expandOnHover м—Ҷмқҙ мӮ¬мҡ©: н•ӯмғҒ лқјлІЁ н‘ңмӢң (Extended FAB)
   * - expandOnHoverмҷҖ н•Ёк»ҳ: нҳёлІ„ мӢңм—җл§Ң лқјлІЁ н‘ңмӢң
   */
  label?: string;
  /**
   * нҳёлІ„ мӢң лқјлІЁ нҺјм№Ё л°©н–Ҙ
   * - "right": м•„мқҙмҪҳ мҡ°мёЎмңјлЎң лқјлІЁ нҺјміҗм§җ
   * - "left" : м•„мқҙмҪҳ мўҢмёЎмңјлЎң лқјлІЁ нҺјміҗм§җ
   * label propмқҙ мһҲм–ҙм•ј лҸҷмһ‘н•©лӢҲлӢӨ.
   */
  expandOnHover?: "right" | "left";
  /**
   * м•„мқҙмҪҳ м „мҡ© FAB нҳёлІ„ мӢң н‘ңмӢңн•  нҲҙнҢҒ н…ҚмҠӨнҠё
   * л””мһҗмқё мӢңмҠӨн…ң Tooltip м»ҙнҸ¬л„ҢнҠёлҘј мӮ¬мҡ©н•©лӢҲлӢӨ.
   * labelмқҙ м—Ҷмқ„ л•Ңл§Ң лҸҷмһ‘н•©лӢҲлӢӨ.
   * @example tooltip="м¶”к°Җн•ҳкё°"
   */
  tooltip?: string;
  /**
   * нҲҙнҢҒ н‘ңмӢң мң„м№ҳ
   * @default "top-center"
   */
  tooltipPlacement?: "top-left" | "top-center" | "top-right" | "bottom-left" | "bottom-center" | "bottom-right";
  /** нҷ”л©ҙ кі м • мң„м№ҳ */
  fixed?: boolean;
  /** fixed мӮ¬мҡ© мӢң мң„м№ҳ м»ӨмҠӨн…Җ (кё°ліё: "bottom-6 right-6") */
  position?: string;
  /**
   * variant кё°ліё мғүмғҒмқ„ overrideн•  Tailwind нҒҙлһҳмҠӨ
   * @example "bg-blue-500 text-white hover:bg-blue-600"
   */
  colorClassName?: string;
}

/* в”Җв”Җ Component в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
const FAB = React.forwardRef<HTMLButtonElement, FABProps>(
  (
    {
      className,
      variant,
      size,
      children,
      label,
      expandOnHover,
      tooltip,
      tooltipPlacement = "top-center",
      fixed = false,
      position = "bottom-6 right-6",
      colorClassName,
      ...props
    },
    ref
  ) => {
    const isExtended    = !!label && !expandOnHover;
    const isExpandable  = !!label && !!expandOnHover;
    const hasTooltip    = !!tooltip && !label;
    const iconSizeClass = getIconSizeClass(size as string);
    const styledIcon    = cloneIconWithSize(children, iconSizeClass);

    const roundedClass = !!label ? "rounded-2xl" : "rounded-full";
    const pxBase   = size === "md" ? "px-4" : "px-6";
    const wBase    = size === "md" ? "w-[40px]" : "w-[48px]";
    const minWBase = size === "md" ? "min-w-[40px]" : "min-w-[48px]";

    const labelSpan = isExpandable ? (
      <span
        className={cn(
          "whitespace-nowrap",
          "max-w-0 opacity-0",
          "transition-[max-width,opacity,margin] duration-200 ease-in-out",
          "group-hover:max-w-[200px] group-hover:opacity-100",
          expandOnHover === "left" ? "group-hover:mx-2" : "group-hover:mx-2"
        )}
      >
        {label}
      </span>
    ) : null;

    const button = (
      <button
        ref={ref}
        className={cn(
          fabVariants({ variant, size }),
          roundedClass,
          !isExtended && !isExpandable && wBase,
          isExtended && cn(pxBase, "gap-2"),
          isExpandable && cn(
            minWBase,
            "px-3",
            "transition-[padding] duration-200",
            "hover:px-4",
            expandOnHover === "left" ? "flex-row-reverse" : "flex-row"
          ),
          colorClassName,
          fixed && `fixed z-modal ${position}`,
          className
        )}
        {...props}
      >
        {labelSpan}
        <span className="shrink-0 flex items-center" aria-hidden="true">
          {styledIcon}
        </span>
        {isExtended && (
          <span className="whitespace-nowrap">{label}</span>
        )}
      </button>
    );

    // нҲҙнҢҒмқҖ л””мһҗмқё мӢңмҠӨн…ң Tooltip м»ҙнҸ¬л„ҢнҠёлЎң к°җмӢём„ң л ҢлҚ”л§Ғ
    if (hasTooltip) {
      return (
        <Tooltip content={tooltip} placement={tooltipPlacement}>
          {button}
        </Tooltip>
      );
    }

    return button;
  }
);

FAB.displayName = "FAB";

export { FAB, fabVariants };