"use client";

import * as React from "react";
import { ChevronLeft, ChevronRight, ChevronUp, ChevronDown } from "lucide-react";
import { cn } from "@/utils/cn";

/* в”Җв”Җ Types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
export type CarouselOrientation = "horizontal" | "vertical";
export type CarouselNavStyle    = "default" | "line" | "border" | "text";
export type CarouselDotsType    = "rounded" | "line" | "border";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   Context
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
interface CarouselContextValue {
  current: number;          // нҳ„мһ¬ мҠ¬лқјмқҙл“ң мқёлҚұмҠӨ
  total: number;            // м „мІҙ м•„мқҙн…ң мҲҳ
  itemsPerView: number;     // н•ң лІҲм—җ ліҙмқҙлҠ” м•„мқҙн…ң мҲҳ
  pageCount: number;        // мқҙлҸҷ к°ҖлҠҘн•ң нҺҳмқҙм§Җ мҲҳ = total - itemsPerView + 1
  orientation: CarouselOrientation;
  loop: boolean;
  prev: () => void;
  next: () => void;
  goTo: (index: number) => void;
  setTotal: (n: number) => void;
}

const CarouselContext = React.createContext<CarouselContextValue | null>(null);

function useCarousel() {
  const ctx = React.useContext(CarouselContext);
  if (!ctx) throw new Error("Must be used within <Carousel>");
  return ctx;
}

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   Carousel (Root)
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface CarouselProps extends React.HTMLAttributes<HTMLDivElement> {
  /** мҠ¬лқјмқҙл“ң л°©н–Ҙ */
  orientation?: CarouselOrientation;
  /** л¬ҙн•ң лЈЁн”„ м—¬л¶Җ */
  loop?: boolean;
  /** мҙҲкё° мқёлҚұмҠӨ (uncontrolled) */
  defaultIndex?: number;
  /** нҳ„мһ¬ мқёлҚұмҠӨ (controlled) */
  index?: number;
  onIndexChange?: (index: number) => void;
  /** н•ң лІҲм—җ ліҙмқҙлҠ” м•„мқҙн…ң мҲҳ вҖ” Multi Carousel */
  itemsPerView?: number;
}

const Carousel = React.forwardRef<HTMLDivElement, CarouselProps>(
  (
    {
      className,
      orientation = "horizontal",
      loop = false,
      defaultIndex = 0,
      index,
      onIndexChange,
      itemsPerView = 1,
      children,
      ...props
    },
    ref
  ) => {
    const [internalIndex, setInternalIndex] = React.useState(defaultIndex);
    const [total, setTotal] = React.useState(0);

    const controlled  = index !== undefined;
    const current     = controlled ? index! : internalIndex;
    const pageCount   = Math.max(1, total - itemsPerView + 1);
    const maxIndex    = Math.max(0, total - itemsPerView);

    const goTo = React.useCallback(
      (i: number) => {
        const next = loop
          ? ((i % pageCount) + pageCount) % pageCount
          : Math.max(0, Math.min(i, maxIndex));
        if (!controlled) setInternalIndex(next);
        onIndexChange?.(next);
      },
      [loop, pageCount, maxIndex, controlled, onIndexChange]
    );

    const prev = React.useCallback(() => goTo(current - 1), [current, goTo]);
    const next = React.useCallback(() => goTo(current + 1), [current, goTo]);

    /* л“ңлһҳк·ё/мҠӨмҷҖмқҙн”„ */
    const dragStart = React.useRef<number | null>(null);
    const onPointerDown = (e: React.PointerEvent) => {
      dragStart.current = orientation === "horizontal" ? e.clientX : e.clientY;
    };
    const onPointerUp = (e: React.PointerEvent) => {
      if (dragStart.current === null) return;
      const delta = (orientation === "horizontal" ? e.clientX : e.clientY) - dragStart.current;
      if (Math.abs(delta) > 40) delta < 0 ? next() : prev();
      dragStart.current = null;
    };

    return (
      <CarouselContext.Provider
        value={{ current, total, itemsPerView, pageCount, orientation, loop, prev, next, goTo, setTotal }}
      >
        <div
          ref={ref}
          role="region"
          aria-roledescription="carousel"
          className={cn("relative select-none", className)}
          onPointerDown={onPointerDown}
          onPointerUp={onPointerUp}
          {...props}
        >
          {children}
        </div>
      </CarouselContext.Provider>
    );
  }
);
Carousel.displayName = "Carousel";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   CarouselContent вҖ” мҠ¬лқјмқҙл“ң нҠёлһҷ
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface CarouselContentProps extends React.HTMLAttributes<HTMLDivElement> {}

const CarouselContent = React.forwardRef<HTMLDivElement, CarouselContentProps>(
  ({ className, children, ...props }, ref) => {
    const { current, orientation, itemsPerView, setTotal } = useCarousel();
    const isHorizontal = orientation === "horizontal";

    const items = React.Children.toArray(children);

    React.useLayoutEffect(() => {
      setTotal(items.length);
    }, [items.length]); // eslint-disable-line

    const translatePct = current * (100 / itemsPerView);

    return (
      <div ref={ref} className={cn("overflow-hidden", className)} {...props}>
        <div
          aria-live="polite"
          className={cn(
            "flex transition-transform duration-slow ease-in-out",
            !isHorizontal && "flex-col h-full"
          )}
          style={{
            transform: isHorizontal
              ? `translateX(-${translatePct}%)`
              : `translateY(-${translatePct}%)`,
          }}
        >
          {items.map((item, i) => (
            <div
              key={i}
              role="group"
              aria-roledescription="slide"
              aria-label={`${i + 1}лІҲм§ё мҠ¬лқјмқҙл“ң`}
              className="shrink-0"
              style={{
                width:  isHorizontal ? `${100 / itemsPerView}%` : "100%",
                height: !isHorizontal ? `${100 / itemsPerView}%` : undefined,
              }}
            >
              {item}
            </div>
          ))}
        </div>
      </div>
    );
  }
);
CarouselContent.displayName = "CarouselContent";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   CarouselItem
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
const CarouselItem = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("w-full h-full", className)} {...props} />
  )
);
CarouselItem.displayName = "CarouselItem";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   CarouselPrevious / CarouselNext
   navStyle: default | line | border | text
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
const navBase = [
  "inline-flex items-center justify-center shrink-0",
  "transition-colors duration-normal",
  "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
  "disabled:pointer-events-none disabled:opacity-30",
].join(" ");

const navStyles: Record<CarouselNavStyle, string> = {
  default: "w-8 h-8 rounded-full bg-ac-white shadow-sm hover:bg-ac-gray-20",
  line:    "w-8 h-8 rounded-full bg-ac-white border border-ac-gray-30 hover:bg-ac-gray-20",
  border:  "w-8 h-8 rounded-full bg-ac-white border border-ac-gray-40 shadow-xs hover:bg-ac-gray-20",
  text:    "px-2 text-sm text-ac-gray-60 hover:text-foreground",
};

export interface CarouselNavButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  navStyle?: CarouselNavStyle;
}

const CarouselPrevious = React.forwardRef<HTMLButtonElement, CarouselNavButtonProps>(
  ({ className, navStyle = "default", ...props }, ref) => {
    const { prev, current, orientation, loop } = useCarousel();
    const Icon = orientation === "horizontal" ? ChevronLeft : ChevronUp;
    const isDisabled = !loop && current === 0;

    return (
      <button
        ref={ref}
        type="button"
        aria-label="мқҙм „ мҠ¬лқјмқҙл“ң"
        disabled={isDisabled}
        onClick={prev}
        className={cn(navBase, navStyles[navStyle], className)}
        {...props}
      >
        <Icon className="w-4 h-4" />
      </button>
    );
  }
);
CarouselPrevious.displayName = "CarouselPrevious";

const CarouselNext = React.forwardRef<HTMLButtonElement, CarouselNavButtonProps>(
  ({ className, navStyle = "default", ...props }, ref) => {
    const { next, current, pageCount, orientation, loop } = useCarousel();
    const Icon = orientation === "horizontal" ? ChevronRight : ChevronDown;
    const isDisabled = !loop && current >= pageCount - 1;

    return (
      <button
        ref={ref}
        type="button"
        aria-label="лӢӨмқҢ мҠ¬лқјмқҙл“ң"
        disabled={isDisabled}
        onClick={next}
        className={cn(navBase, navStyles[navStyle], className)}
        {...props}
      >
        <Icon className="w-4 h-4" />
      </button>
    );
  }
);
CarouselNext.displayName = "CarouselNext";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   CarouselDots вҖ” мқёл””мјҖмқҙн„° dots
   pageCount кё°мӨҖмңјлЎң л ҢлҚ” (Multi Carousel лҢҖмқ‘)
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface CarouselDotsProps extends React.HTMLAttributes<HTMLDivElement> {
  activeColor?: string;
  type?: CarouselDotsType;
}

const CarouselDots = React.forwardRef<HTMLDivElement, CarouselDotsProps>(
  ({ className, activeColor, type = "rounded", ...props }, ref) => {
    const { current, pageCount, goTo, orientation } = useCarousel();
    const rawColor = activeColor ?? "#FF6300";
    const color = rawColor.startsWith("#") || rawColor.startsWith("rgb") || rawColor.startsWith("hsl") || rawColor.startsWith("var(")
      ? rawColor
      : `var(--${rawColor})`;
    const isVertical = orientation === "vertical";

    return (
      <div
        ref={ref}
        role="tablist"
        aria-label="мҠ¬лқјмқҙл“ң м„ нғқ"
        className={cn(
          "flex items-center justify-center gap-2",
          isVertical && "flex-col",
          className
        )}
        {...props}
      >
        {Array.from({ length: pageCount }).map((_, i) => {
          const isActive = i === current;
          const baseBtn = "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring transition-all duration-normal";

          if (type === "line") {
            return (
              <button
                key={i}
                role="tab"
                type="button"
                aria-selected={isActive}
                aria-label={`${i + 1}лІҲм§ё мҠ¬лқјмқҙл“ң`}
                onClick={() => goTo(i)}
                className={baseBtn}
                style={{
                  width: 12,
                  height: 3,
                  borderRadius: 4,
                  backgroundColor: isActive ? color : "#D9D9D9",
                }}
              />
            );
          }

          if (type === "border") {
            return isActive ? (
              <button
                key={i}
                role="tab"
                type="button"
                aria-selected={true}
                aria-label={`${i + 1}лІҲм§ё мҠ¬лқјмқҙл“ң`}
                onClick={() => goTo(i)}
                className={cn("flex items-center justify-center rounded-full", baseBtn)}
                style={{ width: 14, height: 14, border: `1px solid ${color}` }}
              >
                <span style={{ width: 6, height: 6, borderRadius: 9999, backgroundColor: color, display: "block" }} />
              </button>
            ) : (
              <button
                key={i}
                role="tab"
                type="button"
                aria-selected={false}
                aria-label={`${i + 1}лІҲм§ё мҠ¬лқјмқҙл“ң`}
                onClick={() => goTo(i)}
                className={cn("rounded-full", baseBtn)}
                style={{ width: 8, height: 8, backgroundColor: "#ECECEC" }}
              />
            );
          }

          // rounded (default)
          return (
            <button
              key={i}
              role="tab"
              type="button"
              aria-selected={isActive}
              aria-label={`${i + 1}лІҲм§ё мҠ¬лқјмқҙл“ң`}
              onClick={() => goTo(i)}
              className={cn("rounded-full", baseBtn)}
              style={{ width: 8, height: 8, backgroundColor: isActive ? color : "#ECECEC" }}
            />
          );
        })}
      </div>
    );
  }
);
CarouselDots.displayName = "CarouselDots";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   CarouselCounter вҖ” "n / N" м№ҙмҡҙн„°
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
const CarouselCounter = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => {
    const { current, pageCount } = useCarousel();
    return (
      <div
        ref={ref}
        aria-live="polite"
        aria-atomic="true"
        className={cn("text-sm tabular-nums", className)}
        {...props}
      >
        <span style={{ fontWeight: 700, color: "#000000" }}>{current + 1}</span>
        <span style={{ color: "#555555" }}> / </span>
        <span style={{ color: "#555555" }}>{pageCount}</span>
      </div>
    );
  }
);
