"use client";

import * as React from "react";
import { ChevronRight, ExternalLink } from "lucide-react";
import { cn } from "@/utils/cn";
import { Checkbox } from "@/components/Input/Checkbox";
import { Radio } from "@/components/Input/Radio";
import { Avatar } from "@/components/Avatar";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   Types
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export type DropdownAlign    = "start" | "center" | "end";
export type DropdownSide     = "top" | "bottom" | "left" | "right";
export type DropdownItemType = "default" | "checkbox" | "radio" | "small" | "label" | "separator";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   Context
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
interface DropdownContextValue {
  open: boolean;
  setOpen: (v: boolean) => void;
  triggerRef: React.RefObject<HTMLElement>;
  side: DropdownSide;
  align: DropdownAlign;
  anchorPoint: { x: number; y: number } | null;
}

const DropdownContext = React.createContext<DropdownContextValue | null>(null);

function useDropdown() {
  const ctx = React.useContext(DropdownContext);
  if (!ctx) throw new Error("Must be used within <Dropdown>");
  return ctx;
}

/* в”Җв”Җ Sub dropdown context в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */
const SubDropdownContext = React.createContext<{
  openSub: string | null;
  setOpenSub: (id: string | null) => void;
} | null>(null);

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   Dropdown (Root)
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface DropdownProps {
  open?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  side?: DropdownSide;
  align?: DropdownAlign;
  /** л“ңлЎӯлӢӨмҡҙ м—ҙлҰј л°©мӢқ: нҒҙлҰӯ, нҳёлІ„, лҳҗлҠ” мҡ°нҒҙлҰӯ @default "click" */
  trigger?: "click" | "hover" | "contextmenu";
  children: React.ReactNode;
}

function Dropdown({
  open: controlledOpen,
  defaultOpen = false,
  onOpenChange,
  side = "bottom",
  align = "start",
  trigger = "click",
  children,
}: DropdownProps) {
  const [internalOpen, setInternalOpen] = React.useState(defaultOpen);
  const controlled = controlledOpen !== undefined;
  const open = controlled ? controlledOpen! : internalOpen;
  const triggerRef = React.useRef<HTMLElement>(null!);
  const [anchorPoint, setAnchorPoint] = React.useState<{ x: number; y: number } | null>(null);

  const setOpen = React.useCallback((v: boolean) => {
    if (!controlled) setInternalOpen(v);
    onOpenChange?.(v);
  }, [controlled, onOpenChange]);

  // мҷёл¶Җ нҒҙлҰӯ лӢ«кё° (click / contextmenu лӘЁл“ң)
  const containerRef = React.useRef<HTMLDivElement>(null);
  React.useEffect(() => {
    if ((trigger !== "click" && trigger !== "contextmenu") || !open) return;
    const handler = (e: MouseEvent) => {
      if (trigger === "contextmenu") {
        setOpen(false);
        return;
      }
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };
    document.addEventListener(trigger === "contextmenu" ? "click" : "mousedown", handler);
    return () => document.removeEventListener(trigger === "contextmenu" ? "click" : "mousedown", handler);
  }, [trigger, open, setOpen]);

  // ESC лӢ«кё°
  React.useEffect(() => {
    if (!open) return;
    const handler = (e: KeyboardEvent) => { if (e.key === "Escape") setOpen(false); };
    document.addEventListener("keydown", handler);
    return () => document.removeEventListener("keydown", handler);
  }, [open, setOpen]);

  const hoverProps = trigger === "hover" ? {
    onMouseEnter: () => setOpen(true),
    onMouseLeave: () => setOpen(false),
  } : {};

  const contextMenuProps = trigger === "contextmenu" ? {
    onContextMenu: (e: React.MouseEvent) => {
      e.preventDefault();
      setAnchorPoint({ x: e.clientX, y: e.clientY });
      setOpen(true);
    },
  } : {};

  return (
    <DropdownContext.Provider value={{ open, setOpen, triggerRef, side, align, anchorPoint }}>
      <div ref={containerRef} className="relative inline-block" {...hoverProps} {...contextMenuProps}>
        {children}
      </div>
    </DropdownContext.Provider>
  );
}
Dropdown.displayName = "Dropdown";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownTrigger
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface DropdownTriggerProps extends React.HTMLAttributes<HTMLElement> {
  asChild?: boolean;
  disabled?: boolean;
}

function DropdownTrigger({ children, asChild, disabled, onClick, ...props }: DropdownTriggerProps) {
  const { setOpen, open, triggerRef } = useDropdown();

  const handleClick = (e: React.MouseEvent) => {
    if (disabled) return;
    (onClick as any)?.(e);
    setOpen(!open);
  };

  if (asChild && React.isValidElement(children)) {
    return React.cloneElement(children as React.ReactElement<any>, {
      ref: triggerRef,
      onClick: handleClick,
      "aria-haspopup": "menu",
      "aria-expanded": open,
      disabled,
    });
  }

  return (
    <button
      ref={triggerRef as React.RefObject<HTMLButtonElement>}
      type="button"
      onClick={handleClick}
      aria-haspopup="menu"
      aria-expanded={open}
      disabled={disabled}
      {...(props as any)}
    >
      {children}
    </button>
  );
}
DropdownTrigger.displayName = "DropdownTrigger";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   мң„м№ҳ кі„мӮ° н—¬нҚј
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
function getSideAlignClass(side: DropdownSide, align: DropdownAlign): string {
  const sideMap: Record<DropdownSide, string> = {
    bottom: "top-full mt-1",
    top:    "bottom-full mb-1",
    left:   "right-full mr-1 top-0",
    right:  "left-full ml-1 top-0",
  };
  const alignMapV: Record<DropdownAlign, string> = {
    start:  "left-0",
    center: "left-1/2 -translate-x-1/2",
    end:    "right-0",
  };
  const alignMapH: Record<DropdownAlign, string> = {
    start:  "top-0",
    center: "top-1/2 -translate-y-1/2",
    end:    "bottom-0",
  };

  const isVertical = side === "top" || side === "bottom";
  return cn(sideMap[side], isVertical ? alignMapV[align] : alignMapH[align]);
}

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownContent
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface DropdownContentProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "title"> {
  minWidth?: number | string;
}

const DropdownContent = React.forwardRef<HTMLDivElement, DropdownContentProps>(
  ({ className, children, minWidth = 160, ...props }, ref) => {
    const { open, side, align, anchorPoint } = useDropdown();
    const [openSub, setOpenSub] = React.useState<string | null>(null);

    if (!open) return null;

    // contextmenu лӘЁл“ң: м»Өм„ң мң„м№ҳм—җ fixedлЎң л ҢлҚ”л§Ғ
    if (anchorPoint) {
      return (
        <SubDropdownContext.Provider value={{ openSub, setOpenSub }}>
          <div
            ref={ref}
            role="menu"
            aria-orientation="vertical"
            className={cn(
              "fixed z-dropdown",
              "bg-background rounded-md border border-border shadow-md",
              "py-1 animate-scale-in",
              className
            )}
            style={{ minWidth, top: anchorPoint.y, left: anchorPoint.x }}
            {...props}
          >
            {children}
          </div>
        </SubDropdownContext.Provider>
      );
    }

    return (
      <SubDropdownContext.Provider value={{ openSub, setOpenSub }}>
        {/* нҸ¬м§Җм…”лӢқ wrapper: translateмҷҖ animate transform м¶©лҸҢ л°©м§Җ */}
        <div className={cn("absolute z-dropdown", getSideAlignClass(side, align))}>
          <div
            ref={ref}
            role="menu"
            aria-orientation="vertical"
            className={cn(
              "bg-background rounded-md border border-border shadow-md",
              "py-1 animate-scale-in",
              className
            )}
            style={{ minWidth }}
            {...props}
          >
            {children}
          </div>
        </div>
      </SubDropdownContext.Provider>
    );
  }
);
DropdownContent.displayName = "DropdownContent";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownLabel вҖ” к·ёлЈ№ л Ҳмқҙлё” (л№„нҷңм„ұ)
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
const DropdownLabel = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      className={cn("px-3 py-1 text-xs font-medium text-muted-foreground select-none", className)}
      {...props}
    />
  )
);
DropdownLabel.displayName = "DropdownLabel";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownSeparator
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
const DropdownSeparator = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} role="separator" className={cn("my-1 h-px bg-border mx-0", className)} {...props} />
  )
);
DropdownSeparator.displayName = "DropdownSeparator";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownItem вҖ” кё°ліё м•„мқҙн…ң
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface DropdownItemProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "title"> {
  /** мўҢмёЎ м•„мқҙмҪҳ */
  icon?: React.ReactNode;
  /** мҡ°мёЎ лӢЁм¶•нӮӨ нһҢнҠё */
  shortcut?: string;
  /** мҷёл¶Җ л§ҒнҒ¬ м•„мқҙмҪҳ н‘ңмӢң */
  external?: boolean;
  /** мҡ°мёЎ chevron (sub dropdownмҡ©) */
  hasSubmenu?: boolean;
  disabled?: boolean;
  /** small мӮ¬мқҙмҰҲ */
  small?: boolean;
  onSelect?: () => void;
}

const DropdownItem = React.forwardRef<HTMLDivElement, DropdownItemProps>(
  (
    {
      className, children, icon, shortcut, external,
      hasSubmenu, disabled, small, onSelect, onClick, ...props
    },
    ref
  ) => {
    const { setOpen } = useDropdown();

    const handleClick = (e: React.MouseEvent<HTMLDivElement>) => {
      if (disabled) return;
      onClick?.(e);
      onSelect?.();
      if (!hasSubmenu) setOpen(false);
    };

    return (
      <div
        ref={ref}
        role="menuitem"
        aria-disabled={disabled}
        tabIndex={disabled ? -1 : 0}
        onClick={handleClick}
        onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") handleClick(e as any); }}
        className={cn(
          "flex items-center gap-2 w-full cursor-pointer select-none",
          "transition-colors duration-fast",
          small ? "px-3 py-1.5 text-xs" : "px-3 py-2 text-sm",
          disabled
            ? "text-muted-foreground opacity-50 cursor-not-allowed pointer-events-none"
            : "text-foreground hover:bg-ac-gray-20",
          className
        )}
        {...props}
      >
        {icon && <span className="shrink-0 w-4 h-4 flex items-center justify-center text-muted-foreground">{icon}</span>}
        <span className="flex-1 min-w-0 truncate">{children}</span>
        {shortcut && <span className="shrink-0 text-xs text-muted-foreground ml-auto pl-4 tabular-nums">{shortcut}</span>}
        {external && <ExternalLink className="shrink-0 w-3 h-3 text-muted-foreground ml-auto" />}
        {hasSubmenu && <ChevronRight className="shrink-0 w-4 h-4 text-muted-foreground ml-auto" />}
      </div>
    );
  }
);
DropdownItem.displayName = "DropdownItem";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownCheckboxItem вҖ” кё°мЎҙ Checkbox м»ҙнҸ¬л„ҢнҠё мһ¬мӮ¬мҡ©
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface DropdownCheckboxItemProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "title"> {
  checked?: boolean;
  defaultChecked?: boolean;
  onCheckedChange?: (checked: boolean) => void;
  disabled?: boolean;
  icon?: React.ReactNode;
}

const DropdownCheckboxItem = React.forwardRef<HTMLDivElement, DropdownCheckboxItemProps>(
  ({ className, children, checked: controlledChecked, defaultChecked = false, onCheckedChange, disabled, icon, ...props }, ref) => {
    const [internalChecked, setInternalChecked] = React.useState(defaultChecked);
    const controlled = controlledChecked !== undefined;
    const checked = controlled ? controlledChecked! : internalChecked;

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const next = e.target.checked;
      if (!controlled) setInternalChecked(next);
      onCheckedChange?.(next);
    };

    return (
      <div
        ref={ref}
        role="menuitemcheckbox"
        aria-checked={checked}
        className={cn(
          "flex items-center gap-2 px-3 py-2 text-sm w-full select-none",
          "transition-colors duration-fast",
          disabled ? "opacity-50 pointer-events-none" : "hover:bg-ac-gray-20",
          className
        )}
        {...props}
      >
        <Checkbox
          size="lg"
          checked={checked}
          disabled={disabled}
          onChange={handleChange}
          onClick={(e) => e.stopPropagation()}
        />
        {icon && <span className="shrink-0 w-4 h-4 flex items-center justify-center text-muted-foreground">{icon}</span>}
        <span className="flex-1 min-w-0 truncate text-foreground">{children}</span>
      </div>
    );
  }
);
DropdownCheckboxItem.displayName = "DropdownCheckboxItem";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownRadioGroup + DropdownRadioItem
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
const DropdownRadioContext = React.createContext<{
  value: string;
  onValueChange: (v: string) => void;
} | null>(null);

export interface DropdownRadioGroupProps extends React.HTMLAttributes<HTMLDivElement> {
  value?: string;
  defaultValue?: string;
  onValueChange?: (value: string) => void;
}

function DropdownRadioGroup({ value: controlledValue, defaultValue = "", onValueChange, children, ...props }: DropdownRadioGroupProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue);
  const controlled = controlledValue !== undefined;
  const value = controlled ? controlledValue! : internalValue;

  const handleChange = (v: string) => {
    if (!controlled) setInternalValue(v);
    onValueChange?.(v);
  };

  return (
    <DropdownRadioContext.Provider value={{ value, onValueChange: handleChange }}>
      <div role="group" {...props}>{children}</div>
    </DropdownRadioContext.Provider>
  );
}
DropdownRadioGroup.displayName = "DropdownRadioGroup";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownRadioItem вҖ” кё°мЎҙ Radio м»ҙнҸ¬л„ҢнҠё мһ¬мӮ¬мҡ©
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface DropdownRadioItemProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "title"> {
  value: string;
  disabled?: boolean;
  icon?: React.ReactNode;
}

const DropdownRadioItem = React.forwardRef<HTMLDivElement, DropdownRadioItemProps>(
  ({ className, children, value, disabled, icon, ...props }, ref) => {
    const radioCtx = React.useContext(DropdownRadioContext);
    const checked = radioCtx?.value === value;

    const handleChange = () => {
      if (!disabled) radioCtx?.onValueChange(value);
    };

    return (
      <div
        ref={ref}
        role="menuitemradio"
        aria-checked={checked}
        className={cn(
          "flex items-center gap-2 px-3 py-2 text-sm w-full select-none",
          "transition-colors duration-fast",
          disabled ? "opacity-50 pointer-events-none" : "hover:bg-ac-gray-20",
          className
        )}
        {...props}
      >
        <Radio
          size="lg"
          checked={checked}
          disabled={disabled}
          onChange={handleChange}
          onClick={(e) => e.stopPropagation()}
        />
        {icon && <span className="shrink-0 w-4 h-4 flex items-center justify-center text-muted-foreground">{icon}</span>}
        <span className="flex-1 min-w-0 truncate text-foreground">{children}</span>
      </div>
    );
  }
);
DropdownRadioItem.displayName = "DropdownRadioItem";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownAvatarHeader вҖ” л№„нҷңм„ұ м•„л°”нғҖ н—ӨлҚ” (кі„м • м •ліҙ л“ұ)
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface DropdownAvatarHeaderProps extends React.HTMLAttributes<HTMLDivElement> {
  /** м•„л°”нғҖ мқҙлҜём§Җ URL */
  src?: string;
  /** мқҙлҰ„ (мқҙлӢҲм…ң мғқм„ұм—җ мӮ¬мҡ©) */
  name?: string;
  /** мЈј н…ҚмҠӨнҠё */
  label: string;
  /** л¶Җ н…ҚмҠӨнҠё (мқҙл©”мқј л“ұ) */
  description?: string;
}

const DropdownAvatarHeader = React.forwardRef<HTMLDivElement, DropdownAvatarHeaderProps>(
  ({ className, src, name, label, description, ...props }, ref) => (
    <div
      ref={ref}
      className={cn("flex items-center gap-2 px-3 py-2 select-none", className)}
      {...props}
    >
      <Avatar src={src} name={name} size="sm" />
      <div className="flex flex-col min-w-0">
        <span className="text-xs font-medium text-foreground leading-tight">{label}</span>
        {description && (
          <span className="text-xs text-muted-foreground truncate leading-tight">{description}</span>
        )}
      </div>
    </div>
  )
);
DropdownAvatarHeader.displayName = "DropdownAvatarHeader";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownAvatarItem вҖ” нҒҙлҰӯ к°ҖлҠҘн•ң м•„л°”нғҖ м•„мқҙн…ң (мң м Җ лӘ©лЎқ л“ұ)
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface DropdownAvatarItemProps extends React.HTMLAttributes<HTMLDivElement> {
  /** м•„л°”нғҖ мқҙлҜём§Җ URL */
  src?: string;
  /** мқҙлҰ„ (мқҙлӢҲм…ң мғқм„ұм—җ мӮ¬мҡ©) */
  name?: string;
  /** мЈј н…ҚмҠӨнҠё */
  label: string;
  /** л¶Җ н…ҚмҠӨнҠё (мқҙл©”мқј л“ұ) */
  description?: string;
  disabled?: boolean;
  onSelect?: () => void;
}

const DropdownAvatarItem = React.forwardRef<HTMLDivElement, DropdownAvatarItemProps>(
  ({ className, src, name, label, description, disabled, onSelect, onClick, ...props }, ref) => {
    const { setOpen } = useDropdown();

    const handleClick = (e: React.MouseEvent<HTMLDivElement>) => {
      if (disabled) return;
      onClick?.(e);
      onSelect?.();
      setOpen(false);
    };

    return (
      <div
        ref={ref}
        role="menuitem"
        aria-disabled={disabled}
        tabIndex={disabled ? -1 : 0}
        onClick={handleClick}
        onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") handleClick(e as any); }}
        className={cn(
          "flex items-center gap-2 px-3 py-2 w-full cursor-pointer select-none",
          "transition-colors duration-fast",
          disabled
            ? "opacity-50 cursor-not-allowed pointer-events-none"
            : "hover:bg-ac-gray-20",
          className
        )}
        {...props}
      >
        <Avatar src={src} name={name} size="sm" />
        <div className="flex flex-col min-w-0">
          <span className="text-xs font-medium text-foreground leading-tight">{label}</span>
          {description && (
            <span className="text-xs text-muted-foreground truncate leading-tight">{description}</span>
          )}
        </div>
      </div>
    );
  }
);
DropdownAvatarItem.displayName = "DropdownAvatarItem";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   DropdownSubMenu вҖ” Sub dropdown
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export interface DropdownSubMenuProps {
  id: string;
  trigger: React.ReactNode;
  children: React.ReactNode;
  disabled?: boolean;
}

function DropdownSubMenu({ id, trigger, children, disabled }: DropdownSubMenuProps) {
  const subCtx = React.useContext(SubDropdownContext);
  const isOpen = subCtx?.openSub === id;
  const ref = React.useRef<HTMLDivElement>(null);

  const handleMouseEnter = () => { if (!disabled) subCtx?.setOpenSub(id); };
  const handleMouseLeave = () => subCtx?.setOpenSub(null);

  return (
    <div
      ref={ref}
      className="relative"
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      {/* нҠёлҰ¬кұ° м•„мқҙн…ң */}
      <div
        role="menuitem"
        aria-haspopup="menu"
        aria-expanded={isOpen}
        aria-disabled={disabled}
        className={cn(
          "flex items-center gap-2 px-3 py-2 text-sm w-full cursor-pointer select-none",
          "transition-colors duration-fast",
          disabled
            ? "text-muted-foreground opacity-50 cursor-not-allowed pointer-events-none"
            : "text-foreground hover:bg-ac-gray-20"
        )}
      >
        <span className="flex-1 min-w-0 truncate">{trigger}</span>
        <ChevronRight className="shrink-0 w-4 h-4 text-muted-foreground" />
      </div>

      {/* Sub panel */}
      {isOpen && (
        <div
          role="menu"
          className={cn(
            "absolute left-full top-0 ml-1 z-dropdown",
            "bg-background rounded-md border border-border shadow-md",
            "py-1 min-w-[160px] animate-scale-in"
          )}
        >
          {children}
        </div>
      )}
    </div>
  );
}
DropdownSubMenu.displayName = "DropdownSubMenu";

/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
   Exports
в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */
export {
  Dropdown,
  DropdownTrigger,
  DropdownContent,
  DropdownLabel,
  DropdownSeparator,
  DropdownItem,
  DropdownCheckboxItem,
  DropdownRadioGroup,
  DropdownRadioItem,
  DropdownAvatarHeader,
  DropdownAvatarItem,
  DropdownSubMenu,
};